@@ -0,0 +1,78 @@
+/**
+ * Sanitization utilities for embeddable content
+ * Prevents XSS attacks from untrusted HTML content
+ */
+
+const HTML_ENTITIES: Record<string, string> = {
+  "&": "&amp;",
+  "<": "&lt;",
+  ">": "&gt;",
+  '"': "&quot;",
+  "'": "&#x27;",
+};
+
+/**
+ * Escapes HTML special characters to prevent XSS
+ */
+export function escapeHtml(str: string): string {
+  return str.replace(/[&<>"']/g, (char) => HTML_ENTITIES[char]);
+}
+
+/**
+ * Escapes HTML attribute values
+ * Handles both quote contexts and prevents attribute injection
+ */
+export function escapeHtmlAttribute(str: string): string {
+  return escapeHtml(str).replace(/\//g, "&#x2F;");
+}
+
+/**
+ * Sanitizes HTML content for use in srcdoc
+ * Parses and reconstructs HTML to prevent injection attacks
+ */
+export function sanitizeHTML(html: string): string {
+  if (!html || typeof html !== "string") {
+    return "";
+  }
+
+  // Parse the HTML content
+  const parser = new DOMParser();
+  const doc = parser.parseFromString(html, "text/html");
+
+  // Remove dangerous elements
+  const dangerousElements = doc.querySelectorAll(
+    "script, iframe, object, embed, form, meta, link, base"
+  );
+  dangerousElements.forEach((el) => el.remove());
+
+  // Sanitize all remaining elements' attributes
+  const allElements = doc.querySelectorAll("*");
+  allElements.forEach((el) => {
+    // Remove event handlers and dangerous attributes
+    const attrs = Array.from(el.attributes);
+    for (const attr of attrs) {
+      const name = attr.name.toLowerCase();
+      // Remove event handlers (on*)
+      if (name.startsWith("on")) {
+        el.removeAttribute(attr.name);
+      }
+      // Remove javascript: URLs
+      if (
+        (name === "href" || name === "src") &&
+        attr.value.toLowerCase().startsWith("javascript:")
+      ) {
+        el.removeAttribute(attr.name);
+      }
+      // Remove data: URLs in src (except images)
+      if (
+        name === "src" &&
+        attr.value.toLowerCase().startsWith("data:") &&
+        el.tagName.toLowerCase() !== "img"
+      ) {
+        el.removeAttribute(attr.name);
+      }
+    }
+  });
+
+  // Return serialized HTML
+  return doc.body.innerHTML;
+}

